import React from 'react';
import { useNavigate } from "react-router-dom";
import "./Home.css";

const LINKEDIN_PROFILE = "https://www.linkedin.com/in/ton-profil";

const Home: React.FC = () => {
    const navigate = useNavigate();

    const handleNavigateToAbout = () => navigate("/me");
    const handleNavigateToProjects = () => navigate("/project");

    return (
        <div className="home-main">
            <div className="home-container">
                <div className="home-header">
                    <p className="home-title">Recherche d'alternance :</p>
                    <p className="home-subtitle">Développeur informatique</p>
                </div>
                <div>
                    <p className="home-description">
                        Passionné par la programmation, je conçois, développe et déploie des applications,
                        sites web, logiciels et automatisations. Toujours prêt à relever de nouveaux défis,
                        je cherche un stage pour mettre mes compétences en action.
                        Et si ça matche, je serais aussi partant pour une alternance de deux ans à partir d'octobre 2025
                    </p>
                </div>
            </div>
            <div className="home-actions">
                <button
                    className="home-button"
                    type="button"
                    onClick={handleNavigateToAbout}
                >
                    En savoir plus sur moi
                </button>
                <a
                    href={LINKEDIN_PROFILE}
                    target="_blank"
                    rel="noreferrer"
                >
                    <img src="/Logo/moi.svg" alt="LinkedIn"/>
                </a>
                <button
                    className="home-button"
                    type="button"
                    onClick={handleNavigateToProjects}
                >
                    Découvrir mes projets
                </button>
            </div>
        </div>
    );
};

export default Home;
